commands.examples:
CREATE USER 'app_user'@'localhost' IDENTIFIED BY 'SecureP@ss123';
CREATE USER 'api_user'@'%' IDENTIFIED BY 'ApiP@ss456';
CREATE USER 'readonly'@'192.168.1.%' IDENTIFIED BY 'ReadOnly789';

GRANT ALL PRIVILEGES ON myapp.* TO 'app_user'@'localhost';
GRANT SELECT ON myapp.* TO 'readonly'@'%';
GRANT SELECT, INSERT, UPDATE ON myapp.orders TO 'api_user'@'%';
GRANT EXECUTE ON PROCEDURE myapp.GetUserOrders TO 'api_user'@'%';
FLUSH PRIVILEGES;

REVOKE INSERT ON myapp.* FROM 'readonly'@'%';
REVOKE ALL PRIVILEGES ON myapp.* FROM 'old_user'@'localhost';
FLUSH PRIVILEGES;

SHOW GRANTS FOR 'app_user'@'localhost';
SHOW GRANTS FOR CURRENT_USER;
SELECT user, host FROM mysql.user;

ALTER USER 'app_user'@'localhost' IDENTIFIED BY 'NewP@ss123';
ALTER USER 'old_user'@'localhost' ACCOUNT LOCK;
ALTER USER 'old_user'@'localhost' ACCOUNT UNLOCK;
